package Numberprograming;

public class NegativeNumber {

	public static void main(String[] args) {//DB
		// TODO Auto-generated method stub
		for(int i = 0; i <= 10; i++){

            if(i == 0){
                System.out.print(i);
            }
            else{
                System.out.print(", -" + i);
            }
        }

	}

}
